INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Single binary deployment$q$, $q$File Browser compiles to one Go executable with the frontend embedded, so it can be deployed by copying a single file or running one Docker container, with no separate database or runtime needed.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Web-based file operations$q$, $q$Upload, download, rename, move, copy, delete, and create files and folders entirely from the browser, with drag-and-drop support for uploads.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$In-browser preview and editing$q$, $q$Preview images, videos (including MKV playback), PDFs, and markdown files, and edit text and code files directly in an embedded editor without downloading them first.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Multi-user permissions$q$, $q$Create multiple accounts, each scoped to its own home directory with granular rules for uploads, downloads, editing, sharing, and visibility of specific files or folders.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Shareable links$q$, $q$Generate shareable download links for individual files or folders, optionally protected with a password and an expiration time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Command Runner automation$q$, $q$Trigger custom shell scripts on events such as uploads, downloads, or logins, enabling automated backups, transcoding, or notification workflows.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Theming and branding$q$, $q$Customize the interface with light and dark themes, custom CSS, and a branding folder for replacing default logos and styling.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Flexible configuration$q$, $q$Configure the server through CLI flags, FB_-prefixed environment variables, or a .filebrowser JSON, TOML, or YAML config file that is auto-discovered on startup.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Completely free and open source under the permissive Apache 2.0 license, with no paid tiers or usage limits.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Single-binary, dependency-free deployment makes it one of the fastest self-hosted tools to get running via Docker or a bare-metal executable.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Lightweight resource footprint compared to full sync suites like Nextcloud, making it well suited to small VPS instances or home NAS devices.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Large, mature GitHub community (over 35,000 stars) with community translations into 30-plus languages and extensive third-party deployment guides.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$The core project is in maintenance-only mode as of 2026, meaning no new features are being added by the original maintainers, only bug fixes and security patches.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Scoped to a single local directory by default, with no built-in support for cloud storage backends such as S3 or Dropbox the way some alternatives offer.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Users who want actively developed features like OIDC/LDAP single sign-on, multiple storage sources, or OnlyOffice integration need to switch to the community fork File Browser Quantum instead.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$No official managed hosting option; every deployment is fully self-managed, which requires basic server administration knowledge.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Is File Browser really free?$q$, $q$Yes. File Browser is fully free and open source under the Apache License 2.0. There is no paid tier, subscription, or hosted service operated by the project; you self-host it on your own server or NAS at no license cost.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$What operating systems and platforms does File Browser run on?$q$, $q$File Browser compiles to a single Go binary available for Linux, macOS, Windows, and ARM-based devices, and an official Docker image is provided, making it straightforward to run on a home server, VPS, or NAS.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Is File Browser still actively developed?$q$, $q$The original filebrowser/filebrowser project entered maintenance-only mode in 2026, focused on security and bug fixes rather than new features. Active feature development now largely happens in the community fork File Browser Quantum.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Can multiple users have different permissions in File Browser?$q$, $q$Yes. Administrators can create multiple user accounts, each assigned a home directory and granular permission rules covering uploads, downloads, editing, and visibility of specific files or folders.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Does File Browser support cloud storage backends like S3 or Dropbox?$q$, $q$The core File Browser project is scoped to a single local directory and does not include built-in cloud storage adapters. Users needing multi-source or cloud-backend support typically use the File Browser Quantum fork instead.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$What is File Browser Quantum and how is it different?$q$, $q$File Browser Quantum is a community fork (maintained by gtsteffaniak) that carries forward active feature development after the original project moved to maintenance-only mode, adding capabilities such as multiple storage sources, OIDC/LDAP/2FA authentication, and OnlyOffice document editing.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Personal cloud storage on a home server or NAS$q$, $q$Homelab users deploy File Browser on a Raspberry Pi, NAS, or home server to get a Dropbox-like web interface for their own files without relying on a third-party cloud provider.$q$, $q$Homelab and self-hosting enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Lightweight file sharing for small teams$q$, $q$Small businesses or teams use File Browser to expose a shared directory to colleagues with individual accounts and permissions, avoiding the overhead of setting up SFTP access for non-technical staff.$q$, $q$Small business owners and IT admins$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Serving build artifacts and logs on a dev server$q$, $q$Developers run File Browser alongside CI/CD pipelines or application servers to give a quick, browsable web front end to build outputs, logs, or backups stored on the server's filesystem.$q$, $q$Developers and DevOps engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted single-binary deployment","Unlimited users and storage limited only by server disk space","All core features included at no cost","Community support via GitHub issues and documentation"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$File Browser is a free, open-source, self-hosted web application that exposes a single directory on a server as a browsable, manageable personal cloud storage system. Users point the tool at a folder, and it serves a clean web interface for uploading, previewing, editing, and organizing the files inside that folder, without requiring a full operating-system-level file manager or third-party cloud account.$q$, $q$It ships as a single compiled Go binary with an embedded Vue.js frontend, which makes installation as simple as downloading one executable or running the official Docker image. There is no separate database server to install, no build step to run, and no paid tier: everything documented on filebrowser.org is available for free under the Apache License 2.0.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The application supports the core file-management operations users expect from a cloud drive: drag-and-drop uploads, downloads, renaming, moving, copying, deleting, and creating new files and folders. It includes an in-browser text and code editor, image and video preview (including MKV playback), and image thumbnail generation for faster browsing of large media directories.$q$, $q$Administrators can create multiple user accounts, each with its own home directory and a granular set of permissions covering uploads, downloads, editing, sharing, and visibility of specific paths. A 'Command Runner' feature lets admins trigger custom shell scripts on events like uploads or logins, useful for automated backups or notifications. The interface can be themed with custom CSS and branding assets, and it is community-translated into more than thirty languages.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$architecture-and-setup$q$, $q$Architecture and Setup$q$, 2, ARRAY[$q$File Browser configuration is handled through command-line flags, FB_-prefixed environment variables, or an auto-discovered .filebrowser configuration file in JSON, TOML, or YAML format. A companion CLI (the same binary with subcommands) initializes the embedded database and manages users, making it scriptable for infrastructure-as-code deployments.$q$, $q$Because the project entered maintenance-only mode in 2026, with maintainers focused on bug fixes and security patches rather than new features, users who need actively developed capabilities such as single sign-on, multiple storage sources, or OnlyOffice document editing typically look at the community fork File Browser Quantum, which reached a stable v1.4.0 release in June 2026.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$File Browser has no pricing tiers, license fees, or hosted SaaS offering. It is entirely free and open source under the Apache License 2.0, and the full feature set is available to anyone who self-hosts the binary or Docker image. The only cost is the user's own server infrastructure and bandwidth.$q$]::text[], 3);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e72088e-b35d-4326-9a4b-87a7536c4484', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Multi-user, role-based access$q$, $q$Create admin and regular user accounts, each scoped to its own home folder, with a hierarchy that lets a superuser view and manage subfolders belonging to other users.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Pluggable storage adapters$q$, $q$Powered by Flysystem, FileGator can serve files from local disk, FTP, SFTP, Amazon S3, DigitalOcean Spaces, Azure Blob Storage, Dropbox, and other supported backends through one unified interface.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Chunked, resumable uploads$q$, $q$Drag-and-drop uploads use Resumable.js to split large files into chunks that can be paused and resumed, helping large transfers succeed over unreliable connections and around strict PHP upload limits.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Full file operation set$q$, $q$Copy, move, rename, edit, create, delete, preview, zip, unzip, download, and upload files and folders directly from the browser.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Flexible authentication$q$, $q$Authenticate users against a simple JSON file, a database, or an existing WordPress installation, making it easier to integrate FileGator into an existing user system.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$In-app search$q$, $q$Search for files across the current folder and its subfolder tree without leaving the web interface.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$No database required$q$, $q$The default configuration stores users and settings in a JSON file, so FileGator can run on a minimal PHP and web-server stack with no separate database server.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Docker support$q$, $q$An official Docker image is available for containerized deployment alongside the traditional PHP and Apache or Nginx installation path.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Completely free and open source under the permissive MIT license, with no paid tiers, subscriptions, or usage limits.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Built-in support for multiple storage backends (local, FTP, SFTP, S3, Azure, Dropbox) via Flysystem, unlike simpler single-directory file managers.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Multi-user, hierarchical permission model makes it well suited to client portals or team environments needing isolated, scoped access.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Runs without a database server by default, keeping installation lightweight on a basic PHP and web-server stack, with an official Docker image also available.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Smaller community than some alternatives, with roughly 3,000 GitHub stars, meaning fewer third-party guides, plugins, and community support threads.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Default installation places the repository folder under the web root, requiring administrators to correctly configure .htaccess or Nginx protections to prevent script execution risks.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Symlink support is officially described as unofficial and requires manual code changes, which is a gap for administrators relying on symbolic links.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Customization relies on editing configuration files and CSS directly rather than a plugin or extension marketplace, which requires more hands-on PHP familiarity.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Is FileGator free to use?$q$, $q$Yes. FileGator is free and open source under the MIT License, with no paid tiers or subscription fees. You self-host it on your own PHP-capable server at no licensing cost.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$What storage backends does FileGator support?$q$, $q$Through the Flysystem library, FileGator supports local disk storage by default, plus adapters for FTP, SFTP, Amazon S3, DigitalOcean Spaces, Microsoft Azure Blob Storage, Dropbox, and other Flysystem-compatible backends.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Does FileGator require a database?$q$, $q$No. The default configuration stores users and settings in a JSON file, so FileGator can run on a minimal PHP and web-server stack. Database-backed and WordPress-integrated authentication are also supported for installations that need them.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Can FileGator support multiple users with different permissions?$q$, $q$Yes. FileGator ships with admin and regular user roles, per-user home folders, and a hierarchy where a superuser can view and manage subfolders belonging to other users, making it suitable for client portals or team environments.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$How do uploads work in FileGator?$q$, $q$Uploads use Resumable.js for drag-and-drop, chunked, pausable, and resumable transfers, which helps large files succeed on unreliable connections and can be used to work around restrictive PHP upload_max_filesize limits.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$How is FileGator different from File Browser?$q$, $q$FileGator is a PHP application built around Flysystem, offering multiple storage backends (S3, FTP, Dropbox, and more) and hierarchical multi-user roles, while File Browser is a single Go binary scoped to one local directory. FileGator suits multi-backend, multi-user deployments; File Browser favors minimal-footprint simplicity.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Client file exchange portal$q$, $q$Agencies and freelancers deploy FileGator so each client gets an isolated home folder to upload and download project files, without exposing the rest of the server or requiring FTP client software.$q$, $q$Agencies and freelance service providers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Unified interface across cloud and on-premise storage$q$, $q$IT teams use FileGator's Flysystem-backed adapters to present files spread across local disks, S3 buckets, and FTP servers through a single consistent web interface, rather than juggling multiple tools.$q$, $q$IT administrators managing mixed storage environments$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Internal team document repository$q$, $q$Small teams run FileGator on an internal server to give employees scoped, permissioned access to shared documents, using its role hierarchy to separate admin and regular user access.$q$, $q$Small business and internal IT teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted PHP deployment with no database required","Unlimited users and configurable storage backends","Full access to all storage adapters (local, FTP, SFTP, S3, Azure, Dropbox)","Community support via GitHub issues and documentation"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$FileGator is a free, open-source, self-hosted web application for managing files and folders, built as a PHP backend paired with a Vue.js single-page frontend. It was created by developer Milos Stojanovic, with its GitHub repository dating back to June 2019, and has since grown into a multi-user, multi-backend file management platform rather than a simple upload script.$q$, $q$The defining architectural choice is its use of the Flysystem library on the backend, which lets FileGator serve files not just from local disk but from FTP, SFTP, Amazon S3, DigitalOcean Spaces, Azure Blob Storage, Dropbox, and other supported storage adapters, all behind a single web interface with role-based permissions.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$FileGator supports the standard file operations: copy, move, rename, edit, create, delete, preview, zip, unzip, download, and upload. Uploads are handled with Resumable.js, giving drag-and-drop, chunked, pausable, and resumable transfers that help large files succeed over unreliable connections and work around restrictive PHP upload limits.$q$, $q$Multi-user support is built in from the start, with admin and regular user roles, per-user home folders, and a hierarchy in which a superuser can view and manage subfolders belonging to other users. Authentication can be backed by a simple JSON file, a database, or an existing WordPress user base, and the interface itself is styled with the Bulma CSS framework and Buefy component library.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$architecture-and-setup$q$, $q$Architecture and Setup$q$, 2, ARRAY[$q$FileGator requires no database server for its default JSON-file configuration, and can run on any standard PHP and Apache or Nginx stack, or via the official Docker image. Setup involves copying the application files to the server, granting the web process read-write access to the config and repository folders, logging in with the documented default administrator account, and immediately changing the default password.$q$, $q$Because the repository folder sits under the web root in a basic install, FileGator includes protections such as an .htaccess rule to block script execution inside uploaded content, and an optional URL-action encryption setting; administrators applying the same protections manually are recommended when deploying behind Nginx.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$FileGator is entirely free and open source under the MIT License, with no paid plans, subscriptions, or hosted commercial offering. A public live demo exists purely for evaluation. All documented features, including every storage adapter and the multi-user permission system, are available to anyone who self-hosts the code at no licensing cost.$q$]::text[], 3);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ba9e98b-5119-4b61-bcba-6f4764974281', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Web-based Drive-like file manager$q$, $q$A polished browser interface for browsing, uploading, previewing, and organizing files that already exist on the customer's own server, with no required migration into a proprietary format.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Desktop and mobile sync clients$q$, $q$Native apps for Windows, Mac, Linux, iOS, and Android provide folder synchronization comparable to consumer cloud-sync tools, but pointed at self-hosted storage.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Office document editing integrations$q$, $q$Built-in integration with ONLYOFFICE, Collabora Online, LibreOffice Online, Google Docs, Microsoft 365, and Zoho Docs for in-browser document creation and editing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Enterprise authentication$q$, $q$Supports LDAP, Active Directory, OAuth2, Authentik, and WordPress login integration, letting FileRun plug into an existing corporate identity provider.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$White-label branding and app publishing$q$, $q$Businesses and resellers can apply custom logos and color themes and publish their own branded desktop and mobile apps built on FileRun.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Standard-protocol access with no lock-in$q$, $q$Files remain reachable through standard WebDAV and HTTP, so data stays portable outside FileRun's own interface.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$NAS and low-resource deployment support$q$, $q$Documented compatibility with Synology, Unraid, and TrueNAS, plus Docker, VM, and bare-metal installs, with marketing emphasis on running well on budget or legacy hardware.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$35-language localized interface$q$, $q$The interface has 100 percent translation coverage across 35 languages, an unusually broad localization footprint for a self-hosted file manager.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Per-user annual licensing (EUR10/user/year) rather than per-gigabyte storage fees keeps costs predictable as data volume grows.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Complete data ownership since files stay on the customer's own server, NAS, or VPS.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Runs efficiently on modest or legacy hardware, making it viable for small NAS boxes and low-spec VPS instances.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Deep native integrations with ONLYOFFICE, Collabora, Google Docs, and Microsoft 365 for in-browser document editing.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$White-label branding lets agencies and resellers offer FileRun under their own name.$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Nearly two decades of continuous product development behind the current release line.$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Closed-source, commercially licensed software — the code cannot be audited or self-patched the way an open-source alternative like Nextcloud can be.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$The free Family tier is explicitly restricted to non-commercial, non-work use, so businesses always pay per user.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Requires the customer to provision, secure, and maintain their own server, database (MySQL/MariaDB), and PHP environment.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Narrower in scope than groupware-style competitors — no built-in calendar, contacts, chat, or video conferencing the way Nextcloud offers.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Support responsiveness and installation help are gated by plan tier, with the fastest response times reserved for the largest (100+ user) accounts.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Headquarters and company-size details are not published, which may matter for procurement teams doing vendor due diligence.$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Is FileRun free to use?$q$, $q$Only for personal, non-commercial use through the EUR99 one-time Family plan, which explicitly excludes work, freelance, or family-business use. All business use requires a paid per-user annual license starting at EUR10 per user per year.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Is FileRun open source?$q$, $q$No. FileRun is closed-source commercial software distributed under a paid license and protected with the ionCube PHP loader; it is self-hosted but not open source.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$What are the server requirements for FileRun?$q$, $q$FileRun requires PHP 8.3 or 8.4, the ionCube Loader extension, a MySQL or MariaDB database, SSL, and cron support, plus Libvips, ImageMagick, or GraphicsMagick for generating file thumbnails and previews.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Can FileRun run on a NAS device?$q$, $q$Yes. FileRun's own documentation and marketing specifically list Synology, Unraid, and TrueNAS as supported deployment targets, alongside Docker, VMs, and bare-metal Linux or Windows servers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Does FileRun support editing Office documents in the browser?$q$, $q$Yes, through integrations with ONLYOFFICE, Collabora Online, and LibreOffice Online for self-hosted editing, or Google Docs, Microsoft 365, and Zoho Docs for cloud-hosted editing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$How does FileRun differ from Nextcloud?$q$, $q$FileRun focuses narrowly on file management, sharing, and sync with a Drive-like UI, while Nextcloud bundles a broader groupware suite (calendar, contacts, chat, video). Reviewers often rate FileRun's file-sharing UX and mobile apps highly, but Nextcloud offers more collaboration tools beyond storage.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Private cloud storage for small and medium businesses$q$, $q$Replaces consumer services like Dropbox or Google Drive with a self-hosted, per-user-licensed alternative that keeps company files on infrastructure the business controls.$q$, $q$SMB IT administrators and operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$NAS front-end upgrade$q$, $q$Adds a polished, Drive-like web interface, mobile apps, and sharing links on top of existing NAS storage such as Synology, Unraid, or TrueNAS.$q$, $q$Home-lab operators and self-hosting enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Branded client file portal$q$, $q$Uses FileRun's white-label branding and app-publishing features to offer a customized, agency-branded file-sharing portal to end clients.$q$, $q$Agencies, resellers, and service providers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Family$q$, $q$EUR99$q$, $q$One-time (lifetime license)$q$, NULL, $q$["Up to 5 user accounts (+1 added per year)","Lifetime free software updates","Changeable FQDN for expired domains","Community forum access","Non-commercial use only","14-day money-back guarantee"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Small Business$q$, $q$EUR10/user/year$q$, $q$Annual$q$, NULL, $q$["10 or 20 user accounts","Installation-assistance support only","Changeable FQDN if company name changes","Community forum access","30-day money-back guarantee"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Medium Business$q$, $q$EUR10/user/year$q$, $q$Annual$q$, NULL, $q$["30+ user accounts","Email support, 24-hour response for critical issues (Mon-Fri, 9-5)","36-hour response for non-critical issues","Free Docker-based installation service","HTTP, SSH, S/FTP, RDP, and hosting-panel troubleshooting"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$Large Business$q$, $q$EUR10/user/year$q$, $q$Annual$q$, NULL, $q$["100+ user accounts","9 free guest accounts per paid user account","Premium 24-hour support including weekends and holidays","Free installation and server configuration","Extended troubleshooting including desktop sharing"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$FileRun is a self-hosted file manager that gives businesses a private, Google Drive-style interface for storing, sharing, and collaborating on files that live entirely on a server the customer controls. It is installed directly onto existing infrastructure — a Linux or Windows server, a VPS, a virtual machine, bare metal, or a NAS device such as Synology, Unraid, or TrueNAS — and works with files already present on that server's filesystem, so there is no forced migration into a proprietary storage format.$q$, $q$The product is developed by Afian AB and traces its roots to a file manager called Afian first launched in 2003, reworked from 2006 onward, with the first commercial FileRun license sold on July 17, 2007. That long development history has produced a mature, PHP-based application that now follows a year-based release numbering scheme.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$FileRun combines a browser-based file manager with native desktop sync clients for Windows, Mac, and Linux, and mobile apps for iOS and Android, giving it feature parity with consumer cloud-sync tools while keeping data on-premises. It integrates with ONLYOFFICE, Collabora Online, LibreOffice Online, Google Docs, Microsoft 365, and Zoho Docs for in-browser document editing, and supports authentication via LDAP, Active Directory, OAuth2, Authentik, and WordPress for enterprise identity integration.$q$, $q$Administrative features include white-label branding with custom logos and color themes, publishable white-label desktop and mobile apps, file versioning, resumable uploads, unlimited file sizes, and standard WebDAV/HTTP access that avoids vendor lock-in. The interface has full translation coverage in 35 languages, and the underlying stack (PHP 8.3/8.4, MySQL/MariaDB, ionCube Loader, and Libvips/ImageMagick for thumbnails) is documented in detail on FileRun's own support site.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$FileRun sells four tiers, all denominated in euros. The Family plan is a EUR99 one-time lifetime license for up to 5 non-commercial user accounts (plus one added per year), while the three Business plans are each priced at EUR10 per user per year, billed annually, and scale from Small Business (10-20 users, installation-assistance support) through Medium Business (30+ users, weekday email support and free Docker installation) up to Large Business (100+ users, nine free guest accounts per paid seat, and free premium installation with weekend/holiday support).$q$, $q$Because pricing scales per user rather than per gigabyte, FileRun's cost structure is closer to a traditional software license than to consumer cloud storage. The Family plan carries a 14-day money-back guarantee and the Business plans carry a 30-day guarantee, and support scope — from self-service to fully managed installation — expands materially at the higher tiers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c69f3e8f-9780-457f-a312-c387ed3ead8a', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Universal multi-protocol storage gateway$q$, $q$Connects to S3, SFTP, FTP, WebDAV, SMB, NFS, IPFS, Azure, SharePoint, and roughly 25 total backends through one interface, API, and set of protocol gateways (SFTP, S3, FTP, WebDAV, MCP, AS2).$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Plugin-driven architecture$q$, $q$A minimal, opinion-free core with storage backends, authentication, previewers, and behaviors implemented as swappable plugins, following the project's 'everything that matters is a plugin' philosophy.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Enterprise SSO and RBAC$q$, $q$SAML, OIDC, and LDAP single sign-on with role-based access control, available from the Self Served tier upward.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$AI-powered search and OCR$q$, $q$Semantic search, smart folders, and OCR capabilities, with the option to run supporting models locally via Ollama rather than a third-party AI service.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Workflow automation engine$q$, $q$Event-driven automation that can trigger actions in response to file changes across connected storage backends.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Compliance-grade audit logging$q$, $q$Immutable, tamper-proof audit trails aimed at GDPR and broader regulatory compliance for regulated enterprises.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$White-label branding and theming$q$, $q$Multiple UI themes and white-label customization available at the Enterprise tier for organizations that need a branded portal.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Extensive file-format viewers$q$, $q$Built-in app support spanning photography, astronomy, GIS, 3D, and biomedical file formats, beyond generic file preview.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Genuinely free, unlimited-feature open-source Hobby tier under AGPL-3.0 for up to 3 users, with full source code on GitHub.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Connects to virtually any existing storage backend or protocol (S3, SFTP, FTP, WebDAV, SMB, NFS, and more) without requiring data migration.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Strong enterprise security posture in paid tiers: SSO, RBAC, immutable audit logs, and antivirus integration.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Plugin architecture enables deep customization, including support for the Model Context Protocol for AI-agent access.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Validated at scale by named enterprise and academic customers including MIT, JP Morgan, and Monash University.$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Flexible deployment as either self-hosted or managed SaaS at the same price point.$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$The free Hobby tier is capped at just 3 users, so most real teams must move to a paid plan.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Enterprise-grade features (SSO, compliance, white-labeling) are gated behind the $290+/month Enterprise tier, not the entry-level plan.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Self-hosting requires technical setup and ongoing maintenance of the Go-based backend and its dependencies.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Smaller community and ecosystem than broader competitors like Nextcloud.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Company headquarters, team size, and full enterprise pricing are not publicly disclosed, requiring direct sales contact for larger deployments.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$AGPL-3.0's copyleft terms may deter companies that want to build closed-source derivatives on top of the codebase.$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Is Filestash free to use?$q$, $q$Yes. The Hobby tier is free and open source under AGPL-3.0 for self-hosted deployments with up to 3 users. Larger teams or organizations needing SSO and compliance features require the paid Self Served ($50/month) or Enterprise (from $290/month) tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Is Filestash open source?$q$, $q$Yes. Filestash's source code is published on GitHub under the AGPL-3.0 license, with roughly 14,400 stars as of mid-2026. It was previously known as Nuage before being rebranded to Filestash.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$What storage backends does Filestash support?$q$, $q$Filestash connects to S3 and S3-compatible object storage, SFTP, FTP, WebDAV, SMB, NFS, IPFS, Azure, SharePoint, and roughly 25 backends in total, unifying them behind one web interface and API.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Can Filestash be self-hosted?$q$, $q$Yes. Filestash supports both self-hosted deployment and a managed cloud/SaaS deployment at the same pricing, so organizations can choose based on their infrastructure preference rather than paying extra for hosting.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Does Filestash support single sign-on?$q$, $q$Yes, starting at the Self Served tier ($50/month), Filestash supports SAML, OIDC, and LDAP single sign-on with role-based access control.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Who uses Filestash?$q$, $q$Filestash's own marketing names enterprise and academic customers including MIT, JP Morgan, Bell, Orange, UCI, Monash University, Schneider Electric, and government bodies such as the European Commission and Ukraine.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Unified access layer for mixed legacy storage$q$, $q$Gives IT teams a single web interface, access-control model, and audit trail across a mix of SMB shares, FTP servers, NFS mounts, and cloud object storage, without migrating any of it.$q$, $q$Enterprise IT and infrastructure teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Managed file transfer and compliance-grade sharing$q$, $q$Provides SSO, RBAC, and immutable audit logging for regulated organizations that need to prove who accessed which files and when.$q$, $q$Finance, government, and other regulated enterprises$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Self-hosted Dropbox alternative for developers$q$, $q$Runs the free, open-source Hobby tier to get a clean web UI over an S3 bucket, SFTP server, or homelab NAS without any licensing cost.$q$, $q$Developers and self-hosting enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Hobby$q$, $q$Free$q$, $q$N/A (open source, self-hosted)$q$, NULL, $q$["AGPL-3.0 open-source license","Self-hosted deployment","Up to 3 users","Community support (IRC, Open Collective)"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Self Served (Standard)$q$, $q$$50/month$q$, $q$Monthly$q$, NULL, $q$["Commercial license","SSO: SAML, OIDC, LDAP with RBAC","3 seats","Single-node deployment","Self-hosted or managed cloud","Free trial available"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$Enterprise$q$, $q$From $290/month (flexible plans to $750+/month)$q$, $q$Monthly$q$, NULL, $q$["Unlimited users","Audit and compliance tooling","White-labeling","24/7 support","High-availability infrastructure","Dedicated account manager and custom SLA","Managed upgrades and professional/security services","Custom enterprise plugin development"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Filestash is an open-source universal file manager that connects to existing storage — Amazon S3 and S3-compatible object stores, SFTP, FTP, WebDAV, SMB, NFS, IPFS, Azure, SharePoint, and roughly 25 backends in total — and presents them through one consistent web interface, API, and set of protocol gateways. It does not require migrating data into a new proprietary store; instead it acts as a unified access and governance layer on top of storage that already exists.$q$, $q$The project, created by developer Mickael Kerjean, has its GitHub repository dated to June 13, 2017, and was previously known as Nuage before being rebranded to Filestash. It is licensed under AGPL-3.0 and, as of mid-2026, has accumulated roughly 14,400 stars and nearly 1,000 forks on GitHub.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Filestash is built around a plugin-driven architecture — 'everything that matters is a plugin' — which lets storage backends, authentication providers, and file previewers be swapped in and out around a minimal Go-and-JavaScript core. It exposes universal access through a web client, an API, and gateways that let other systems reach Filestash-managed storage over SFTP, S3, FTP, WebDAV, MCP, and AS2.$q$, $q$Additional capabilities include SSO with SAML, OIDC, and LDAP and role-based access control, a workflow engine for automating file-event actions, immutable audit logging for GDPR and compliance, AI-powered semantic search, smart folders and OCR (with local model support via Ollama), antivirus integration, quota management, versioning, and white-label theming.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Filestash offers three published tiers. Hobby is free and open source, self-hosted under AGPL-3.0, capped at up to 3 users. Self Served (Standard) starts at $50 per month for a commercial license with SSO (SAML, OIDC, LDAP) and RBAC on a single-node, 3-seat deployment, available self-hosted or as managed cloud hosting, with a free trial.$q$, $q$Enterprise starts at $290 per month, with flexible plans scaling to $750 per month and beyond for larger deployments, unlocking unlimited users, audit and compliance tooling, white-labeling, 24/7 support, high availability, a dedicated account manager, custom SLAs, and professional services. All plans can cancel anytime and billing runs through Stripe.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
