INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bfbd22a1-7933-401b-b0f3-d85dae77fecd', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$LOIS AI Assistant$q$, $q$A firm-wide AI layer built on a legal knowledge graph of 40 million-plus matters that can draft documents, summarize depositions, and surface case insights across an entire firm, not just a single file.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$Matters (Case Management)$q$, $q$The core module for tracking tasks, deadlines, notes, and case collaboration across a firm's active caseload.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$Intake$q$, $q$Lead capture and case evaluation workflows designed to move prospective clients from first contact into an active matter.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$Depositions$q$, $q$Tools for managing deposition transcripts, testimony tracking, and related case preparation materials.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$Native e-Signatures$q$, $q$Built-in e-signature collection for case documents and client agreements without needing a third-party e-signature tool.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$Document Assembly and Contract Management$q$, $q$Template-driven generation of filings, contracts, and case documents populated automatically from matter data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$Accounting and Billing Integrations$q$, $q$Native integrations with QuickBooks Online, Xero, and LawPay for trust accounting, expense tracking, and billing reconciliation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$Open API and Mobile Apps$q$, $q$A documented REST API for custom automations plus native iOS and Android apps for accessing cases, documents, and tasks on the go.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$AI (LOIS) is deeply embedded across the entire platform rather than offered as a separate bolt-on chat tool.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$Strong reputation among reviewers, with roughly a 4.8/5 rating on G2 and 4.6/5 on Capterra.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$Broad module coverage (intake through depositions to signatures) reduces the need for separate point solutions.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$Backed by substantial, well-known venture investors (Insight Partners, Accel), suggesting long-term platform investment and stability.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$No public pricing; firms must go through a sales process to get a quote, which can slow down evaluation.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$Custom, quote-based pricing makes it harder to comparison-shop against flat-rate competitors like Clio or MyCase.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$Deep, module-based platform can carry a steeper learning curve for very small or solo practices with simple needs.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$Some customer feedback across review sources flags inconsistent support experiences.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$What is Filevine?$q$, $q$Filevine is a cloud-based legal operating system for law firms and legal teams that combines case management, intake, depositions, e-signatures, document assembly, and an AI layer called LOIS into one platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$How much does Filevine cost?$q$, $q$Filevine does not publish fixed pricing. Packages are custom-built based on the modules and seats a firm needs, and pricing is provided through a sales quote after a demo or free trial.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$What is LOIS in Filevine?$q$, $q$LOIS (Legal Operating Intelligence System) is Filevine's AI layer, built on a legal knowledge graph covering more than 40 million matters, that can draft documents, summarize case data, and act across a firm's matters rather than a single file.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$Does Filevine have a mobile app?$q$, $q$Yes. Filevine offers native mobile apps for both iOS and Android so attorneys and staff can access cases, documents, and tasks remotely.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$Who is Filevine best suited for?$q$, $q$Filevine serves solo practitioners through Big Law firms, with particularly deep functionality for personal injury, mass tort, family law, immigration, insurance defense, criminal defense, and estate planning practices, as well as government legal offices.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$What are the main alternatives to Filevine?$q$, $q$Common alternatives include Clio, MyCase, Smokeball, PracticePanther, and CARET Legal, all of which compete in the legal practice management category.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$High-volume personal injury and mass tort practices$q$, $q$Firms managing large caseloads of similar matter types use Filevine's Matters and Intake modules alongside LOIS to standardize workflows and speed up case evaluation and document drafting.$q$, $q$Personal injury and mass tort law firms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$Government legal offices$q$, $q$Prosecutors, public defenders, and state or local agencies use Filevine to manage case files, deadlines, and evidence collaboration across large teams of attorneys.$q$, $q$Public defenders and government legal departments$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$Corporate and Big Law legal departments$q$, $q$Larger legal teams use Filevine's document assembly, contract management, and API integrations to connect case data with existing accounting and business systems.$q$, $q$In-house corporate legal teams and large law firms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$Custom$q$, $q$Custom pricing$q$, $q$Contact sales$q$, NULL, $q$["Package built around selected modules (LOIS, Matters, Intake, Depositions, Signatures)","Seat and matter-volume based pricing","Free trial available before purchase","Dedicated sales consultation and demo"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Filevine is a cloud-based legal operating system that combines case and matter management, intake, depositions, e-signatures, and document assembly into a single platform for law firms, government legal offices, and corporate legal departments.$q$, $q$Founded in 2014 and now headquartered in Salt Lake City, Utah, Filevine has grown into one of the most heavily funded companies in legal technology, having raised roughly $548 million in total venture funding and reaching an estimated $3 billion valuation following a $400 million Series E round in September 2025.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the core of Filevine's modern platform is LOIS (Legal Operating Intelligence System), an AI layer built on a legal knowledge graph drawn from more than 40 million matters, capable of both reading case data and writing directly into a matter, such as drafting motions or summarizing depositions.$q$, $q$Beyond AI, Filevine offers dedicated modules for Matters, Intake, Depositions, and Signatures, a documented public API for custom automations, native iOS and Android mobile apps, and pre-built integrations with accounting and legal tools including QuickBooks Online, Xero, LawPay, and InfoTrack.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Filevine does not publish fixed pricing tiers. Instead, every package is custom-built based on the modules a firm selects (LOIS, Matters, Intake, Depositions, Signatures) and the number of seats required, with pricing determined through a sales consultation.$q$, $q$Prospective customers can start a free trial or book a demo before requesting a formal quote, which is standard practice among enterprise legal case-management vendors whose costs scale with firm size and licensed modules.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('15c3e1d1-3978-4b9a-82fd-8517048b2955', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Native Notion and Airtable Sync$q$, $q$Two-way integration that creates or updates database records the instant a form is submitted, without Zapier, webhooks, or other middleware.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$AI Form Generator$q$, $q$Generates a working form, including relevant fields and logic, from a natural-language prompt.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$50+ Field Types and Conditional Logic$q$, $q$A broad library of question and field types combined with branching logic to build dynamic, multi-path forms.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Payments and E-Signatures$q$, $q$Built-in payment collection and signature capture directly within a form, without a separate checkout or e-signature tool.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Scheduling and PDF Generation$q$, $q$Native calendar booking (including Calendly scheduling) and automatic PDF generation from form submissions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Unlimited Seats on Every Plan$q$, $q$All pricing tiers, including the free plan, include unlimited team seats and unlimited forms, with pricing scaling only by monthly response volume.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Custom Branding and Domains$q$, $q$Higher tiers support custom themes, fonts, CSS, share links, and a fully custom domain for hosting forms.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$30+ Native Integrations$q$, $q$Direct connections to CRM, marketing, and productivity tools beyond Notion and Airtable, reducing dependence on automation platforms.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Generous free plan with 1,000 responses per month and unlimited forms and seats, more permissive than many competitors' free tiers.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Unlimited seats on every paid tier removes the per-user cost penalty common in other form builders.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Native two-way sync with Notion and Airtable avoids the latency and extra cost of Zapier-style automation middleware.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Broad feature set (payments, e-signatures, scheduling, PDF generation) reduces the need for separate point tools.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Paid tiers are gated primarily by monthly response volume, which can require an upgrade sooner for high-traffic forms.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Removing Fillout's own branding requires at least the Pro plan, not available on Free or Starter.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Advanced governance features like SSO and audit logs are reserved for the custom-priced Enterprise tier.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$The company's 2025-2026 restructuring under the Zite parent brand may create some confusion for customers researching the company versus the product.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$What is Fillout used for?$q$, $q$Fillout is a no-code tool for building online forms, surveys, quizzes, and lead-capture pages, with support for payments, e-signatures, scheduling, and PDF generation.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Does Fillout have a free plan?$q$, $q$Yes. Fillout's free plan costs $0 and includes 1,000 responses per month plus unlimited forms, unlimited seats, and access to all 50-plus field types.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$How much do Fillout's paid plans cost?$q$, $q$Paid plans are Starter at $15/month billed annually, Pro at $40/month billed annually, and Business at $75/month billed annually, each raising the monthly response limit and unlocking additional customization and analytics features. An Enterprise plan with custom pricing is also available.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$What makes Fillout different from Typeform or Jotform?$q$, $q$Fillout's key differentiator is native, two-way synchronization with Notion and Airtable that updates records instantly without middleware like Zapier, along with unlimited seats on every plan, including the free tier.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Is Fillout the same company as Zite?$q$, $q$Fillout's parent company was renamed to Zite in 2025-2026, but Fillout continues to operate as its own product at fillout.com with existing accounts and branding intact. Zite is also the name of a newer, separate AI-powered app-building product from the same company.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Who founded Fillout?$q$, $q$Fillout was founded in 2022 by Antony Toron and Dominic Whyte.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Lead capture synced to Airtable or Notion$q$, $q$Marketing and sales teams use Fillout to collect leads through embedded forms that write directly into an existing Notion or Airtable database in real time.$q$, $q$Marketing and sales operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Client intake and payment collection$q$, $q$Agencies and service businesses use Fillout to build intake forms that collect information, e-signatures, and upfront payments in a single step.$q$, $q$Agencies and small service businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Internal surveys and feedback forms$q$, $q$Operations teams use Fillout's unlimited-seat model to let every employee create and share internal surveys or feedback forms without added per-user cost.$q$, $q$Internal operations and HR teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Free$q$, $q$$0$q$, $q$Free forever$q$, NULL, $q$["1,000 responses per month","Unlimited forms, seats, and questions","50+ field types","Embedding, payments, scheduling, PDF generation, conditional logic, file uploads, workflows"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Starter$q$, $q$$15/month (billed annually, $180/year); $19/month billed monthly$q$, $q$Monthly or annual$q$, NULL, $q$["2,000 responses per month","Unlimited seats and forms","All question types, custom endings, login forms","CAPTCHA, premium field types, custom themes and logo","Calendly scheduling and signature collection"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Pro$q$, $q$$40/month (billed annually, $480/year); $49/month billed monthly$q$, $q$Monthly or annual$q$, NULL, $q$["5,000 responses per month","Custom emails and removal of Fillout branding","Custom share links","Custom fonts and favicon","Form preview customization"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Business$q$, $q$$75/month (billed annually, $900/year); $89/month billed monthly$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited responses","Form analytics with conversion tracking","Custom domain","Custom code injection and partial submissions","Priority support and 1GB+ file uploads"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Contact sales$q$, NULL, $q$["Single sign-on (SSO)","1M+ database records","Unlimited workflow runs","Audit logs","Dedicated support and custom SLAs"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Fillout is a no-code online form, survey, and quiz builder that lets users create and embed forms with more than 50 field types, conditional logic, payments, scheduling, and e-signatures, without writing code.$q$, $q$Founded in 2022 by Antony Toron and Dominic Whyte, Fillout has grown to over 100,000 organizations and 10,000-plus paying customers, and now operates under a parent company called Zite while continuing to run as its own standalone product at fillout.com.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Fillout's standout feature is native, two-way synchronization with Notion and Airtable, letting form submissions create or update database records instantly without relying on Zapier or other automation middleware.$q$, $q$The platform also includes an AI form generator that builds forms from a text prompt, more than 30 native integrations, payment collection, PDF generation, scheduling, and unlimited seats on every plan, including the free tier.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Fillout offers a free-forever plan with 1,000 responses per month and unlimited forms and seats, followed by three self-serve paid tiers, Starter ($15/month annually), Pro ($40/month annually), and Business ($75/month annually), each raising the monthly response cap and unlocking branding, analytics, and customization features.$q$, $q$An Enterprise tier above Business offers custom pricing with SSO, large-scale database support, unlimited workflow runs, audit logs, and dedicated support for larger organizations.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e77aef61-9ca8-4e8b-8c7c-e11365f41e17', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
